{"command": "cd /workspace && python3 -c "
import docx
d = docx.Document('output/invoice-review-memo.docx')
# Dump ALL text content (paragraphs + tables) into one stream for grep-style audit
out=[]
for p in d.paragraphs:
    if p.text.strip(): out.append(p.text)
for i,t in enumerate(d.tables):
    out.append(f'[[TABLE {i}]]')
    for r in t.rows:
        out.append(' | '.join(c.text for c in r.cells))
open('/workspace/audit_dump.txt','w').write('\n'.join(out))
print('wrote', len(out), 'blocks')
""}

