{"command": "cd /workspace && echo "=== Rate-cap check for each timekeeper (§ 5.1) ===" && python3 -c "
caps={'Partner':1000,'Senior Associate':650,'Mid-Level Associate':500,'Junior Associate':400,'Contract Attorney':200}
data=[('David Hargrove','Lead Partner',985),('Karen Cho','Senior Associate',625),('James Pettersson','Mid-Level Associate',475),('Nina Barros','Mid-Level Associate',475),('Tyler Webb','Junior Associate',375),('Priya Sengupta','Junior Associate',375),('Marcus Tate','Contract Attorney',210)]
for n,role,rate in data:
    cap=caps[role]
    print(f'{n:20s} {role:22s} rate={rate} cap={cap} {\"WITHIN\" if rate<=cap else \"OVER by \"+str(rate-cap)}')
"
echo ""
echo "=== Scan time-entry narratives for vague/generic ones (§ 9.2) ==="
python3 -c "
import openpyxl
wb = openpyxl.load_workbook('documents/hl-may-2025-invoice.xlsx', data_only=True)
ws = wb['Time Detail']
vague_markers=['legal research','case work','review documents','correspondence','attention to matter','review docs']
for r in ws.iter_rows(min_row=2, values_only=True):
    if r[0] is None or str(r[0])=='SUBTOTAL': continue
    desc=(r[8] or '').strip().lower()
    # flag if very short or matches a bare vague marker as the whole/leading phrase
    words=len(desc.split())
    flag=[]
    if words<=6: flag.append('SHORT('+str(words)+'w)')
    for m in ['review documents','legal research']:
        if desc==m or desc.startswith(m+'.') or desc==m: flag.append('BARE:'+m)
    if flag: print(r[0], r[2], '|', r[8][:80], '||', flag)
print('--- scan complete (no output above = no bare-vague entries) ---')
""}

